  ('social-worker-moex-01581', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者非社會工作專業倫理之目的？', '["社會工作師專業服務指南", "提供社會對於社會工作專業信任的基礎", "促進中央與地方政府對於社會工作專業的重視", "評判社會工作實務適切與否之標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01582', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '根據Reamer（1995）對於業務過失（malpractice）的定義，社會工作師原先計畫和案主一起出席 社區改建的公聽會，卻未事先告知當日無法出席而讓案主獨自出席，這是屬於何種業務過失？', '["瀆職", "濫權", "侵權", "怠職"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01583', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為了預防業務過失，有些社會工作師在執行業務時會採取防衛性實務。下列何者不屬於防衛性實 務？', '["完全按照該機構的服務規定", "撰寫紀錄時只記錄案主的改善情形", "向機構主管爭取與倡導案主所需資源", "依法行事重於一切"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01584', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列那一項不是Beauchamp和Childress（1979）提出的生命倫理學原則？', '["自主原則", "善待原則", "正義原則", "誠信原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01585', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '強調社工專業服務倫理與正當性無關，而是應該依據良善品格而表現道德行為，這是何種倫理學 的主張？', '["義務論觀點", "德行論觀點", "目的論觀點", "專業主義觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01586', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '列為低收入戶的家庭，育有五名未成年子女，夫妻二人均有輕度身心障礙，亦都沒有穩定工作。 近日，再度因疏忽照顧而被列為高風險家庭。經社會工作者瞭解，這個家庭除了政府補助外，也 有多個民間非營利組織與慈善團體提供各種長短期津貼與物資。社會工作者欺騙此夫妻：「通常 不去接受就業輔導的案家，你們的子女就會被強制安置」。下列有關義務論與目的論對「欺騙」 的觀點之敘述，何者錯誤？', '["目的論主張，欺騙是否合宜應視此一行為本身所帶來的好處決定", "目的論主張，欺騙是否合宜應視所屬社會法律有無相關規範決定", "義務論主張，即使欺騙此一行為的動機是良善的，仍然是不對的", "義務論主張，即使欺騙此一行為的結果是有益的，仍然是不對的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01587', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '因年齡增長導致功能逐漸喪失，是高齡者無可避免的生理變化。下列何種評估高齡者的需求不符 合聯合國老人綱領工作原則？', '["評估高齡者依然有能力做的事，非無法做的事", "提高高齡者的自我照顧能力", "獨居高齡者因視力退化，無法騎車到社區據點和友人共餐，送餐服務志工同時可問安，比起交 通接送，更有助於維持長輩原有的社會人際網絡", "高齡者參與服務申請過程，表達自己對服務的期待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01588', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列婦女福利服務方案，何者不屬於婦女人身安全範疇？', '["未婚媽媽自我成長團體", "性侵害案件整合性團隊服務方案", "性侵害案件減少被害人重複陳述", "家庭暴力防治中心的安置庇護服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01589', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '某縣市政府推行托育政策規定幼兒必須是實質送托，家長和機構才能領到補助款。這是屬於何種 形式的兒童福利輸送服務？', '["實物協助（in kind）", "現金給付（in cash）", "代券（voucher）", "家庭維繫（family preservation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01590', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關青少年藥物濫用的形成因素之理論解釋，何者最為適當？', '["社會學習理論（social learning theory）主張是個人判斷能力不足所致", "適應模式（adaptive model）主張是先天性遺傳因子的脆弱性所致", "社會控制理論（social control theory）主張是個人缺乏適當的社會鍵（social bonds）所致", "疾病模式（disease model）主張是外在壓力導致個人的成癮疾病"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
